from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F, types as T

PATH = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.tzfix/_data/gen_payments_seed42.ndjson"

TIME_COLS  = ["event_time","ts","timestamp","occurred_at","created_at","time",
              "paid_at","payment_time","created","datetime"]
CCY_COLS   = ["currency","ccy","currency_code","currency_iso","cur"]
AMT_COLS   = ["amount","value","amt","amount_original","foreign_amount","original_amount"]
RATE_COLS  = ["rate","usd_rate","fx_rate","rate_to_usd","usd_per_unit","conversion_rate"]
RDATE_COLS = ["rate_date","date","as_of","day","effective_date"]

_ALL = TIME_COLS + CCY_COLS + AMT_COLS + RATE_COLS + RDATE_COLS + ["type", "kind"]
SCHEMA = T.StructType([T.StructField(n, T.StringType(), True) for n in dict.fromkeys(_ALL)])


def _first(cols):
    return F.coalesce(*[F.col(c) for c in cols])


def _first_num(cols):
    return F.coalesce(*[F.col(c).cast("double") for c in cols])


def parse_ts(c):
    c = c.cast("string")
    epoch = (c.cast("double") / F.lit(1000.0)).cast("timestamp")
    tagged = F.when(c.rlike(r"(Z|[+-]\d{2}:?\d{2})$"), c).otherwise(F.concat(c, F.lit("Z")))
    return F.when(c.rlike(r"^\d{13,}$"), epoch).otherwise(F.to_timestamp(tagged))


def utc_day(ts):
    # render the instant in UTC before taking the calendar date (session-tz independent)
    return F.to_date(F.to_utc_timestamp(ts, F.current_timezone()))


@dp.materialized_view(name="raw_payments")
def raw_payments():
    df = SparkSession.active().read.schema(SCHEMA).json(PATH)
    ts_str = _first(TIME_COLS)
    return df.select(
        ts_str.alias("ts_str"),
        parse_ts(ts_str).alias("event_ts"),
        F.upper(_first(CCY_COLS)).alias("ccy"),
        _first_num(AMT_COLS).alias("amount"),
        _first_num(RATE_COLS).alias("row_rate"),
        _first(RDATE_COLS).alias("rate_day_str"),
    )


@dp.materialized_view(name="fx_rates")
def fx_rates():
    df = SparkSession.active().read.table("spark_catalog.default.raw_payments")
    # dedicated rate records: carry a rate but no payment amount
    r = df.where(F.col("row_rate").isNotNull() & F.col("amount").isNull())
    rate_day = F.to_date(F.substring(F.col("rate_day_str"), 1, 10))
    r = r.select(
        F.col("ccy").alias("rate_ccy"),
        rate_day.alias("rate_day"),
        F.col("row_rate").alias("fx_rate_raw"),
    ).where(F.col("rate_ccy").isNotNull() & F.col("rate_day").isNotNull())
    return r.groupBy("rate_ccy", "rate_day").agg(F.max("fx_rate_raw").alias("fx_rate"))


def _joined_payments(spark):
    pay = (
        spark.read.table("spark_catalog.default.raw_payments")
        .where(F.col("amount").isNotNull() & F.col("ccy").isNotNull())
    )
    p = pay.select(
        F.col("ccy"),
        F.col("amount"),
        F.col("row_rate"),
        F.col("event_ts"),
        utc_day(F.col("event_ts")).alias("settlement_date"),
    )
    rates = spark.read.table("spark_catalog.default.fx_rates")
    j = p.join(
        rates,
        (p["ccy"] == rates["rate_ccy"]) & (p["settlement_date"] == rates["rate_day"]),
        "left",
    )
    factor = F.when(
        F.col("ccy") == "USD",
        F.coalesce(F.col("fx_rate"), F.col("row_rate"), F.lit(1.0)),
    ).otherwise(F.coalesce(F.col("fx_rate"), F.col("row_rate")))
    return j, factor


@dp.materialized_view(name="usd_daily")
def usd_daily():
    spark = SparkSession.active()
    j, factor = _joined_payments(spark)
    recognized = j.where(F.col("settlement_date").isNotNull() & factor.isNotNull())
    return (
        recognized.select(
            F.col("settlement_date"),
            (F.col("amount") * factor).alias("usd_amount"),
        )
        .groupBy("settlement_date")
        .agg(F.sum("usd_amount").alias("usd_total"))
    )


@dp.materialized_view(name="payments_rejected")
def payments_rejected():
    spark = SparkSession.active()
    j, factor = _joined_payments(spark)
    bad = j.where(F.col("settlement_date").isNull() | factor.isNull())
    reason = F.when(F.col("settlement_date").isNull(), F.lit("unparseable_timestamp")) \
              .otherwise(F.lit("unrecognized_currency"))
    return bad.select(
        F.col("ccy"),
        F.col("amount"),
        F.col("event_ts"),
        reason.alias("reject_reason"),
    )

from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F

PATH = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.tzfix/_data/gen_payments_seed8675.ndjson"
DB = "spark_catalog.default"

# ---- import-time profiling (outside query functions => allowed) ----
try:
    _cols = set(SparkSession.active().read.json(PATH).columns)
except Exception:
    _cols = set()

def C(*cands):
    if not _cols:
        return cands[0]
    for x in cands:
        if x in _cols:
            return x
    return None

AMT   = C("amount", "amount_original", "original_amount", "value", "payment_amount")
CUR   = C("currency", "currency_code", "ccy", "cur")
TS    = C("occurred_at", "event_time", "timestamp", "ts", "time", "paid_at", "created_at")
RATE  = C("usd_rate", "rate", "fx_rate", "rate_to_usd", "usd_per_unit")
RDATE = C("rate_date", "as_of_date", "effective_date", "as_of", "date", "day")

def _c(name):
    return F.col(name) if name else F.lit(None)

def parse_ts(c):
    # c is a string column; handle the three shapes: epoch-millis, offset-aware, naive-UTC
    tagged = F.when(c.rlike(r"(Z|[+-]\d{2}:?\d{2})$"), c).otherwise(F.concat(c, F.lit("Z")))
    return F.when(c.rlike(r"^\d{13,}$"),
                  (c.cast("double") / 1000).cast("timestamp")
                 ).otherwise(F.to_timestamp(tagged))

def utc_day(ts):
    # UTC calendar day, independent of session tz
    return F.to_date(F.to_utc_timestamp(ts, F.current_timezone()))

# row classification: rate rows carry a rate and no amount; payments carry an amount
def is_rate_row():
    return _c(RATE).isNotNull() & _c(AMT).isNull()

def is_pay_row():
    return _c(AMT).isNotNull()


@dp.materialized_view(name="raw_events")
def raw_events():
    return SparkSession.active().read.json(PATH)


@dp.materialized_view(name="fx_rates")
def fx_rates():
    raw = SparkSession.active().read.table(f"{DB}.raw_events")
    r = (raw.where(is_rate_row())
            .select(_c(CUR).cast("string").alias("rcur"),
                    F.to_date(_c(RDATE).cast("string")).alias("rday"),
                    _c(RATE).cast("double").alias("rate")))
    return r.groupBy("rcur", "rday").agg(F.avg("rate").alias("rate"))


@dp.materialized_view(name="payments_parsed")
def payments_parsed():
    raw = SparkSession.active().read.table(f"{DB}.raw_events")
    p = (raw.where(is_pay_row())
            .select(_c(CUR).cast("string").alias("currency"),
                    _c(AMT).cast("double").alias("amount"),
                    _c(TS).cast("string").alias("ts_str")))
    p = p.withColumn("ts", parse_ts(F.col("ts_str")))
    p = p.withColumn("day", utc_day(F.col("ts")))
    return p


@dp.materialized_view(name="payments_priced")
def payments_priced():
    spark = SparkSession.active()
    pay = spark.read.table(f"{DB}.payments_parsed")
    rates = spark.read.table(f"{DB}.fx_rates")
    j = pay.join(rates,
                 (pay["currency"] == rates["rcur"]) & (pay["day"] == rates["rday"]),
                 "left")
    eff = F.when(F.col("currency") == F.lit("USD"), F.lit(1.0)).otherwise(F.col("rate"))
    j = j.withColumn("eff_rate", eff)
    j = j.withColumn("usd_amount", F.col("amount") * F.col("eff_rate"))
    j = j.withColumn(
        "reject_reason",
        F.when(F.col("day").isNull(), F.lit("unparseable_timestamp"))
         .when(F.col("eff_rate").isNull(), F.lit("unrecognized_currency"))
         .otherwise(F.lit(None)))
    return j.select("currency", "amount", "ts_str", "day",
                    "eff_rate", "usd_amount", "reject_reason")


@dp.materialized_view(name="payment_rejects")
def payment_rejects():
    priced = SparkSession.active().read.table(f"{DB}.payments_priced")
    return priced.where(F.col("reject_reason").isNotNull())


@dp.materialized_view(name="usd_daily")
def usd_daily():
    priced = SparkSession.active().read.table(f"{DB}.payments_priced")
    kept = priced.where(F.col("reject_reason").isNull())
    return (kept.groupBy(F.col("day").alias("settlement_date"))
                .agg(F.sum("usd_amount").alias("usd_total")))

