RATE_CANDS = ["usd_rate", "rate", "fx_rate", "rate_to_usd", "usd_rate_on_day",
              "conversion_rate"]
DATE_CANDS = ["date", "rate_date", "as_of", "day"]


def _first(raw, paths):
    return F.coalesce(*[F.get_json_object(raw, "$." + p) for p in paths])


def _utc_day(c):
    # Session-tz-independent UTC calendar day, robust to 4 shapes.
    date_only = F.when(c.rlike(r"^\d{4}-\d{2}-\d{2}$"), F.to_date(c))
    epoch = F.when(c.rlike(r"^\d{13,}$"), (c.cast("double") / F.lit(1000.0)).cast("timestamp"))
    # naive -> tag as UTC before parse; offset-aware parses to correct instant
    tagged = F.when(c.rlike(r"(Z|[+-]\d{2}:?\d{2})$"), c).otherwise(F.concat(c, F.lit("Z")))
    ts = F.coalesce(epoch, F.to_timestamp(tagged))
    day_from_ts = F.to_date(F.to_utc_timestamp(ts, F.current_timezone()))
    return F.coalesce(date_only, day_from_ts)


@dp.materialized_view(name="payments_bronze")
def payments_bronze():
    return SparkSession.active().read.text(DATASET).withColumnRenamed("value", "raw")


