    raw = F.col("raw")
    amount = _first(raw, AMT_CANDS).cast("double")
    currency = F.upper(F.trim(_first(raw, CUR_CANDS)))
    ts_raw = _first(raw, TS_CANDS)
    rate_inline = _first(raw, RATE_CANDS).cast("double")
    # payment rows are the ones carrying an amount
    return df.select(
        raw.alias("raw"),
        amount.alias("amount"),
        currency.alias("currency"),
        ts_raw.alias("ts_raw"),
        rate_inline.alias("rate_inline"),
        _utc_day(ts_raw).alias("pay_day"),
    ).where(amount.isNotNull())


@dp.materialized_view(name="fx_rates")
