    df = SparkSession.active().read.table("payments_bronze")
    raw = F.col("raw")
    amount = _first(raw, AMT_CANDS).cast("double")
    currency = F.upper(F.trim(_first(raw, CUR_CANDS)))
    rate = _first(raw, RATE_CANDS).cast("double")
    date_raw = F.coalesce(_first(raw, DATE_CANDS), _first(raw, TS_CANDS))
    rows = df.select(
        currency.alias("currency"),
        rate.alias("rate"),
        _utc_day(date_raw).alias("rate_day"),   # identical bucketing rule
    ).where(amount.isNull() & rate.isNotNull() & currency.isNotNull())
    return rows.groupBy("currency", "rate_day").agg(F.avg("rate").alias("rate"))


