        (p["currency"] == r["currency"]) & (p["pay_day"] == r["rate_day"]),
        "left",
    )
    eff = F.coalesce(
        p["rate_inline"],
        r["rate"],
        F.when(p["currency"] == F.lit("USD"), F.lit(1.0)),
    )
    return p, r, joined.withColumn("eff_rate", eff)


@dp.materialized_view(name="usd_daily")
def usd_daily():
