             p["currency"].alias("currency"),
             p["amount"].alias("amount"),
             p["pay_day"].alias("pay_day"),
         )
    )

from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F

DATA_PATH = (
    "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/"
    ".work.tzfix/_data/gen_payments_seed31415.ndjson"
)


def _g(*keys):
    c = F.col("value")
    return F.coalesce(*[F.get_json_object(c, "$." + k) for k in keys])


def _parse_instant(col):
    # three shapes: epoch-millis (all-digit >=13), offset-aware, naive(=UTC wall clock)
    epoch = F.when(col.rlike(r"^\d{13,}$"),
                   (col.cast("double") / F.lit(1000.0)).cast("timestamp"))
    tagged = F.when(col.rlike(r"(Z|[+-]\d{2}:?\d{2})$"), col).otherwise(
        F.concat(col, F.lit("Z")))
    return F.coalesce(epoch, F.to_timestamp(tagged))


def _utc_day(ts):
    # UTC calendar day, independent of session timezone
    return F.to_date(F.to_utc_timestamp(ts, F.current_timezone()))


_CUR = ("currency", "ccy", "curr", "currency_code")
_AMT = ("amount", "value", "payment_amount", "amt", "native_amount")
_TS = ("occurred_at", "event_time", "timestamp", "ts", "paid_at", "time",
       "created_at", "event_ts", "payment_time", "payment_ts")
_RATE = ("rate", "fx_rate", "usd_rate", "rate_to_usd", "usd_per_unit", "fx")
_RDATE = ("date", "as_of", "rate_date", "day", "effective_date", "asof_date",
          "quote_date")


@dp.materialized_view(name="payments_parsed")
def payments_parsed():
    df = SparkSession.active().read.text(DATA_PATH)
    parsed = df.select(
        _g(*_AMT).cast("double").alias("amount"),
        F.upper(F.trim(_g(*_CUR))).alias("currency"),
        _parse_instant(_g(*_TS)).alias("event_ts"),
        _g(*_RATE).cast("double").alias("inline_rate"),
    )
    # payment records are those carrying a monetary amount
    pays = parsed.where(F.col("amount").isNotNull())
    return pays.select(
        "amount", "currency", "inline_rate",
        _utc_day(F.col("event_ts")).alias("event_day"),
    )


@dp.materialized_view(name="rate_dim")
def rate_dim():
    df = SparkSession.active().read.text(DATA_PATH)
    parsed = df.select(
        F.upper(F.trim(_g(*_CUR))).alias("currency"),
        _g(*_RATE).cast("double").alias("rate"),
        _parse_instant(_g(*_RDATE)).alias("rate_ts"),
        _g(*_AMT).alias("amount"),
    )
    # rate records: carry a rate + rate-date, but no payment amount
    rates = parsed.where(
        F.col("rate").isNotNull()
        & F.col("amount").isNull()
        & F.col("rate_ts").isNotNull()
    )
    dim = rates.select(
        "currency", "rate",
        _utc_day(F.col("rate_ts")).alias("rate_day"),
    )
    # one deterministic rate per (currency, UTC day)
    return dim.groupBy("currency", "rate_day").agg(F.max("rate").alias("rate"))


def _joined():
    spark = SparkSession.active()
    pay = spark.read.table("spark_catalog.default.payments_parsed")
    dim = spark.read.table("spark_catalog.default.rate_dim")
    j = pay.join(
        dim,
        (pay["currency"] == dim["rate_day"].isNotNull() & (pay["currency"] == dim["currency"]))
        if False else ((pay["currency"] == dim["currency"]) & (pay["event_day"] == dim["rate_day"])),
        "left",
    )
    eff = F.coalesce(
        F.col("inline_rate"),
        F.when(pay["currency"] == F.lit("USD"), F.lit(1.0)),
        F.col("rate"),
    )
    return j.select(
        pay["event_day"].alias("settlement_date"),
        pay["currency"].alias("currency"),
        F.col("amount").alias("amount"),
        eff.alias("eff_rate"),
        (F.col("amount") * eff).alias("usd_amount"),
    )


@dp.materialized_view(name="usd_daily")
def usd_daily():
    rows = _joined()
    recognized = rows.where(
        F.col("eff_rate").isNotNull() & F.col("settlement_date").isNotNull()
