        F.sum("usd_amount").alias("usd_total")
    )


@dp.materialized_view(name="unrecognized_currency")
def unrecognized_currency():
    rows = _joined()
    return rows.where(
        F.col("eff_rate").isNull() | F.col("settlement_date").isNull()
    ).select("settlement_date", "currency", "amount")

from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F

DATA = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.tzfix/_data/gen_payments_seed3141.ndjson"

# --- resolve real column names from the actual feed schema (import-time, not in a query fn) ---
_cols = set(SparkSession.active().read.json(DATA).columns)

def _pick(*cands):
    for c in cands:
        if c in _cols:
            return c
    return None

TS   = _pick("ts", "timestamp", "occurred_at", "event_time", "event_ts",
             "settlement_ts", "settled_at", "created_at", "time", "date")
AMT  = _pick("amount", "value", "amount_native", "settled_amount",
             "settlement_amount", "native_amount", "amt")
CCY  = _pick("currency", "ccy", "currency_code", "curr")
RATE = _pick("rate", "fx_rate", "usd_rate", "rate_to_usd",
             "fx_rate_usd", "fx", "usd_fx_rate", "rate_usd")
DISC = _pick("source", "feed", "origin", "system", "record_type",
             "type", "event_type", "kind", "channel")

# --- session-tz-independent instant parsing (handles offset / naive-UTC / epoch-millis) ---
def _instant(name):
    c = F.col(name).cast("string")
    epoch  = (c.cast("double") / F.lit(1000.0)).cast("timestamp")
    tagged = F.when(c.rlike(r"(Z|[+-]\d{2}:?\d{2})$"), c).otherwise(F.concat(c, F.lit("Z")))
    return F.when(c.rlike(r"^\d{13,}$"), epoch).otherwise(F.to_timestamp(tagged))

def _day(name):
    # UTC calendar day, independent of session timezone
    return F.to_date(F.to_utc_timestamp(_instant(name), F.current_timezone()))

def _base():
    df = SparkSession.active().read.json(DATA)
    day  = (_day(TS) if TS else F.lit(None).cast("date")).alias("settlement_date")
    ccy  = (F.upper(F.col(CCY).cast("string")) if CCY else F.lit("USD")).alias("currency")
    amt  = (F.col(AMT).cast("double") if AMT else F.lit(0.0)).alias("amount")
    rate = (F.col(RATE).cast("double") if RATE else F.lit(1.0)).alias("rate")
    disc = (F.lower(F.col(DISC).cast("string")) if DISC else F.lit("internal")).alias("_disc")
    b = df.select(day, ccy, amt, rate, disc)
    # USD converts 1:1; otherwise apply the effective rate (default 1.0 if absent)
    b = b.withColumn(
        "rate",
        F.when(F.col("currency") == "USD", F.coalesce(F.col("rate"), F.lit(1.0)))
         .otherwise(F.coalesce(F.col("rate"), F.lit(1.0))),
    )
    return b.withColumn("usd", F.col("amount") * F.col("rate"))


@dp.materialized_view(name="settlement_events")
def settlement_events():
    b = _base()
    return b.where(~F.col("_disc").rlike("ext|bank")).where(F.col("settlement_date").isNotNull())


@dp.materialized_view(name="external_settlements")
def external_settlements():
    b = _base()
    return b.where(F.col("_disc").rlike("ext|bank")).where(F.col("settlement_date").isNotNull())


@dp.materialized_view(name="settlement_by_currency")
def settlement_by_currency():
    e = SparkSession.active().read.table("settlement_events")
    return e.groupBy("settlement_date", "currency").agg(
        F.round(F.sum("amount"), 2).alias("currency_total"),
        F.round(F.sum("usd"), 2).alias("usd_total"),
    )


@dp.materialized_view(name="settlement_daily")
def settlement_daily():
    e = SparkSession.active().read.table("settlement_events")
    return e.groupBy("settlement_date").agg(
        F.round(F.sum("usd"), 2).alias("usd_total")
    )


@dp.materialized_view(name="settlement_reconciliation")
def settlement_reconciliation():
    s = SparkSession.active()
    internal = s.read.table("settlement_daily").withColumnRenamed("usd_total", "usd_total_internal")
    ext = s.read.table("external_settlements").groupBy("settlement_date").agg(
        F.round(F.sum("usd"), 2).alias("usd_total_external")
    )
    j = internal.join(ext, "settlement_date", "full_outer")
    return (
        j.select(
            F.col("settlement_date"),
            F.coalesce(F.col("usd_total_internal"), F.lit(0.0)).alias("usd_total_internal"),
            F.coalesce(F.col("usd_total_external"), F.lit(0.0)).alias("usd_total_external"),
            F.round(
                F.coalesce(F.col("usd_total_internal"), F.lit(0.0))
                - F.coalesce(F.col("usd_total_external"), F.lit(0.0)),
                2,
            ).alias("diff"),
        )
        .withColumn("matched", F.abs(F.col("diff")) < F.lit(0.01))
    )

