def _peek_keys(uri, limit=500):
    path = uri[len("file://"):] if uri.startswith("file://") else uri
    keys = set()
    try:
        with open(path) as f:
            for i, line in enumerate(f):
                if i > limit:
                    break
                line = line.strip()
                if not line:
                    continue
                try:
                    obj = json.loads(line)
                    if isinstance(obj, dict):
                        keys |= set(obj.keys())
                except Exception:
                    pass
    except Exception:
        pass
    return keys


def _pick(keys, cands):
