def _dedup(xs):
    out = []
    for x in xs:
        if x not in out:
            out.append(x)
    return out


def _schema_with_after(names):
    names = _dedup(names)
    sub = StructType([StructField(n, StringType(), True) for n in names])
    fields = [StructField(n, StringType(), True) for n in names]
    fields.append(StructField("after", sub, True))
    fields.append(StructField("before", sub, True))
    return StructType(fields)


def _coalesce(names):
    exprs = []
    for n in names:
        exprs.append(F.col(n).cast("string"))
        exprs.append(F.col("after")[n].cast("string"))
    return F.coalesce(*exprs)


def _parse_ts(col):
    s = col.cast("string")
    epoch = (s.cast("double") / F.lit(1000.0)).cast("timestamp")
    tagged = F.when(s.rlike(r"(Z|[+-]\d{2}:?\d{2})$"), s).otherwise(F.concat(s, F.lit("Z")))
    parsed = F.to_timestamp(tagged)
    return F.when(s.rlike(r"^\d{13,}$"), epoch).otherwise(parsed)


def _utc_day(ts):
    return F.to_date(F.to_utc_timestamp(ts, F.current_timezone()))


