    return (
        df.where(op.isNull() | (~op.isin("D", "DELETE", "DEL")))
        .select(
            F.upper(_coalesce(CCY)).alias("rate_currency"),
            _coalesce(RATE).cast("double").alias("rate"),
            _parse_ts(_coalesce(RTS)).alias("rate_ts"),
        )
        .where(F.col("rate_ts").isNotNull())
    )


