PAY_PATH = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.tzfix/_data/gen_payments_seed27182.ndjson"
FX_PATH  = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.tzfix/_data/gen_fx_rates_cdc_seed27182.ndjson"

# ---- candidate field names (superset schema -> missing ones read as NULL) ----
PAY_ID   = ["payment_id", "id", "txn_id", "transaction_id"]
PAY_AMT  = ["amount", "foreign_amount", "value", "amt", "payment_amount"]
PAY_CCY  = ["currency", "ccy", "currency_code"]
PAY_TS   = ["event_time", "event_ts", "occurred_at", "payment_time", "payment_ts",
            "ts", "timestamp", "created_at"]

FX_CCY   = ["currency", "ccy", "currency_code"]
FX_RATE  = ["rate", "usd_rate", "fx_rate", "rate_to_usd", "price"]
FX_TS    = ["rate_time", "rate_ts", "effective_at", "valid_from", "ts",
            "timestamp", "as_of", "event_time"]


def _schema(*groups):
    names = list(dict.fromkeys([c for g in groups for c in g]))
    return StructType([StructField(n, StringType(), True) for n in names])


def _parse_ts(c):
    # epoch-millis (all-digit, >=13 chars)
    epoch = F.when(c.rlike(r"^\d{13,}$"), (c.cast("double") / 1000).cast("timestamp"))
    # offset-aware kept as-is; naive tagged as UTC before parsing
    tagged = F.when(c.rlike(r"(Z|[+-]\d{2}:?\d{2})$"), c).otherwise(F.concat(c, F.lit("Z")))
    return F.coalesce(epoch, F.to_timestamp(tagged))


def _utc_day(ts):
    # render instant in UTC before taking the calendar date (session-tz independent)
    return F.to_date(F.to_utc_timestamp(ts, F.current_timezone()))


@dp.materialized_view(name="payments_src")
def payments_src():
    df = SparkSession.active().read.schema(_schema(PAY_ID, PAY_AMT, PAY_CCY, PAY_TS)).json(PAY_PATH)
    return df.select(
        F.coalesce(*PAY_ID).alias("payment_id"),
        F.coalesce(*[F.col(c).cast("double") for c in PAY_AMT]).alias("amount"),
        F.coalesce(*PAY_CCY).alias("currency"),
        _parse_ts(F.coalesce(*PAY_TS)).alias("pay_ts"),
    )


@dp.materialized_view(name="rates_src")
def rates_src():
    df = SparkSession.active().read.schema(_schema(FX_CCY, FX_RATE, FX_TS)).json(FX_PATH)
    return df.select(
        F.coalesce(*FX_CCY).alias("currency"),
        F.coalesce(*[F.col(c).cast("double") for c in FX_RATE]).alias("rate"),
        _parse_ts(F.coalesce(*FX_TS)).alias("rate_ts"),
    )


@dp.materialized_view(name="enriched_payments")
def enriched_payments():
    spark = SparkSession.active()
    pay = spark.read.table("spark_catalog.default.payments_src")
    rate = spark.read.table("spark_catalog.default.rates_src")

    # as-of: only rates in effect at or before the payment instant
    cand = pay.join(rate, on="currency", how="inner").where(F.col("rate_ts") <= F.col("pay_ts"))
    w = Window.partitionBy("payment_id").orderBy(F.col("rate_ts").desc())
    best = (
        cand.withColumn("rn", F.row_number().over(w))
        .where(F.col("rn") == 1)
        .select(
            "payment_id",
            F.col("rate").alias("fx_rate"),
            F.col("rate_ts").alias("as_applied_rate_ts"),
        )
    )

    # left join back so no payment (foreign value) is lost
    return (
        pay.join(best, on="payment_id", how="left")
        .select(
            "payment_id",
            "currency",
            F.col("amount").alias("foreign_amount"),
            "pay_ts",
            "fx_rate",
            "as_applied_rate_ts",
            (F.col("amount") * F.col("fx_rate")).alias("usd_amount"),
            _utc_day(F.col("pay_ts")).alias("settlement_date"),
        )
    )


@dp.materialized_view(name="usd_daily")
def usd_daily():
    e = SparkSession.active().read.table("spark_catalog.default.enriched_payments")
    return (
        e.groupBy("settlement_date")
        .agg(F.sum("usd_amount").alias("usd_total"))
        .select("settlement_date", "usd_total")
    )

from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F, Window

PAY = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.tzfix/_data/gen_payments_seed16180.ndjson"
FX  = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.tzfix/_data/gen_fx_rates_cdc_seed16180.ndjson"

CAT = "spark_catalog.default."


def _js(*names):
    """First non-null JSON field among candidate key names (missing key -> NULL, never an error)."""
    v = F.col("value")
    return F.coalesce(*[F.get_json_object(v, "$." + n) for n in names])


def _parse_ts(c):
    """Robust: epoch-millis (all-digit >=13), offset-aware, or naive (=UTC wall clock)."""
    epoch = F.when(c.rlike(r"^\d{13,}$"), (c.cast("double") / 1000).cast("timestamp"))
    tagged = F.when(c.rlike(r"(Z|[+-]\d{2}:?\d{2})$"), c).otherwise(F.concat(c, F.lit("Z")))
    return F.coalesce(epoch, F.to_timestamp(tagged))


def _utc_day(ts):
    # session-tz-independent UTC calendar day
    return F.to_date(F.to_utc_timestamp(ts, F.current_timezone()))


# ---------- raw text ingest (lazy; no schema inference) ----------
@dp.materialized_view(name="payments_raw")
def payments_raw():
    return SparkSession.active().read.text(PAY)


@dp.materialized_view(name="fx_raw")
def fx_raw():
    return SparkSession.active().read.text(FX)


# ---------- parsed dimensions/facts ----------
@dp.materialized_view(name="payments_parsed")
def payments_parsed():
    df = SparkSession.active().read.table(CAT + "payments_raw")
    ts_raw = _js("event_time", "occurred_at", "occurred_ts", "event_ts", "ts",
                 "timestamp", "payment_time", "payment_ts", "created_at", "time")
    return df.select(
        F.monotonically_increasing_id().alias("pay_key"),
        _js("payment_id", "id", "pid", "txn_id", "transaction_id").alias("payment_id"),
        _js("currency", "ccy", "curr", "currency_code", "cur").alias("currency"),
        _js("amount", "foreign_amount", "amount_foreign", "fx_amount",
            "paid_amount", "value", "amt").cast("double").alias("amount"),
        ts_raw.alias("pay_ts_raw"),
        _parse_ts(ts_raw).alias("pay_ts"),
    )


@dp.materialized_view(name="fx_parsed")
def fx_parsed():
    df = SparkSession.active().read.table(CAT + "fx_raw")
    rts_raw = _js("effective_ts", "effective_time", "as_of", "as_of_ts", "valid_from",
                  "rate_ts", "rate_time", "ts", "timestamp", "event_time", "event_ts", "time")
    return df.select(
        _js("currency", "ccy", "curr", "currency_code", "cur").alias("fx_currency"),
        _js("rate", "fx_rate", "usd_rate", "rate_to_usd", "exchange_rate",
            "px", "price").cast("double").alias("rate"),
        _parse_ts(rts_raw).alias("rate_ts"),
    ).where(F.col("rate").isNotNull() & F.col("rate_ts").isNotNull())


# ---------- as-of enrichment: rate in effect at payment instant ----------
@dp.materialized_view(name="enriched_payments")
def enriched_payments():
    spark = SparkSession.active()
    pay = spark.read.table(CAT + "payments_parsed")
    fx = spark.read.table(CAT + "fx_parsed")

    # candidate rates: same currency, stamped at-or-before the payment instant (never after)
    j = pay.join(
        fx,
        (pay["currency"] == fx["fx_currency"]) & (fx["rate_ts"] <= pay["pay_ts"]),
        "left",
    )

    # pick the latest such rate deterministically (tie-break on rate value)
    w = Window.partitionBy("pay_key").orderBy(
        F.col("rate_ts").desc_nulls_last(), F.col("rate").desc_nulls_last()
    )
    ranked = j.withColumn("rn", F.row_number().over(w)).where(F.col("rn") == 1)

    return ranked.select(
        "pay_key",
        "payment_id",
        "currency",
        "amount",                                   # foreign value preserved
        "pay_ts",
        F.col("rate").alias("applied_rate"),
        F.col("rate_ts").alias("applied_rate_ts"),  # as-applied rate timestamp for audit
        (F.col("amount") * F.col("rate")).alias("usd_amount"),
        _utc_day(F.col("pay_ts")).alias("settlement_date"),
    )


# ---------- final contract table ----------
@dp.materialized_view(name="usd_daily")
def usd_daily():
    ep = SparkSession.active().read.table(CAT + "enriched_payments")
    return (
        ep.where(F.col("settlement_date").isNotNull())
          .groupBy("settlement_date")
          .agg(F.sum("usd_amount").alias("usd_total"))
          .select(F.col("settlement_date").cast("date").alias("settlement_date"), "usd_total")
    )

from pyspark import pipelines as dp
from pyspark.sql import SparkSession, functions as F
from pyspark.sql.window import Window
from pyspark.sql.types import StructType, StructField, StringType

PAYMENTS = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.tzfix/_data/gen_payments_seed14142.ndjson"
FX = "file:///home/lnc/repos/ssa-powered-run/experiments/safe_agent_study/.work.tzfix/_data/gen_fx_rates_cdc_seed14142.ndjson"

# ---- candidate field names (superset; missing ones arrive as NULL) ----
ID_FIELDS   = ["payment_id", "id", "txn_id", "transaction_id"]
AMT_FIELDS  = ["amount", "value", "foreign_amount", "amount_foreign", "fx_amount"]
CCY_FIELDS  = ["currency", "ccy", "currency_code"]
PTS_FIELDS  = ["event_time", "event_ts", "occurred_at", "timestamp", "ts",
               "payment_time", "created_at", "paid_at"]

RATE_FIELDS = ["rate", "fx_rate", "usd_rate", "rate_to_usd", "price"]
FTS_FIELDS  = ["rate_ts", "ts", "timestamp", "effective_ts", "as_of",
               "rate_time", "event_time", "updated_at", "valid_from"]

PAY_ALL = ID_FIELDS + AMT_FIELDS + CCY_FIELDS + PTS_FIELDS
FX_ALL  = CCY_FIELDS + RATE_FIELDS + FTS_FIELDS + ["op", "_change_type"]

PAY_SCHEMA = StructType([StructField(f, StringType(), True) for f in dict.fromkeys(PAY_ALL)])
FX_SCHEMA  = StructType([StructField(f, StringType(), True) for f in dict.fromkeys(FX_ALL)])


def _coalesce_str(names):
    return F.coalesce(*[F.col(n) for n in names])


def _coalesce_dbl(names):
    return F.coalesce(*[F.col(n).cast("double") for n in names])


def parse_ts(c):
    c = c.cast("string")
    # epoch-millis branch first, then offset-aware / naive-UTC via to_timestamp
    return F.coalesce(
        F.when(c.rlike(r"^\d{13,}$"), (c.cast("double") / 1000.0).cast("timestamp")),
        F.to_timestamp(
            F.when(c.rlike(r"(Z|[+-]\d{2}:?\d{2})$"), c).otherwise(F.concat(c, F.lit("Z")))
        ),
    )


def utc_day(ts):
    # session-tz-independent UTC calendar day
    return F.to_date(F.to_utc_timestamp(ts, F.current_timezone()))


def load_payments(spark):
    df = spark.read.schema(PAY_SCHEMA).json(PAYMENTS)
    return df.select(
        _coalesce_str(ID_FIELDS).alias("payment_id"),
        F.upper(_coalesce_str(CCY_FIELDS)).alias("currency"),
        _coalesce_dbl(AMT_FIELDS).alias("amount"),
        _coalesce_str(PTS_FIELDS).alias("pay_ts_raw"),
    ).withColumn("pay_ts", parse_ts(F.col("pay_ts_raw")))


def load_rates(spark):
    df = spark.read.schema(FX_SCHEMA).json(FX)
    r = df.select(
        F.upper(_coalesce_str(CCY_FIELDS)).alias("r_ccy"),
        _coalesce_dbl(RATE_FIELDS).alias("rate"),
        _coalesce_str(FTS_FIELDS).alias("rate_ts_raw"),
        F.coalesce(F.col("op"), F.col("_change_type")).alias("op"),
    ).withColumn("rate_ts", parse_ts(F.col("rate_ts_raw")))
    # drop CDC deletes; keep only usable rate observations
    r = r.where(F.col("op").isNull() | (~F.lower(F.col("op")).isin("delete", "d", "delete_marker")))
    return r.where(F.col("rate").isNotNull() & F.col("rate_ts").isNotNull()) \
            .select("r_ccy", "rate", "rate_ts")


def build_enriched(spark):
    pays = load_payments(spark)
    valid = pays.where(
        F.col("pay_ts").isNotNull() & F.col("amount").isNotNull() & F.col("currency").isNotNull()
    ).withColumn("_pid", F.monotonically_increasing_id())

    rates = load_rates(spark)

    # as-of join: only rates in effect AT/BEFORE the payment instant
    cond = (F.col("currency") == F.col("r_ccy")) & (F.col("rate_ts") <= F.col("pay_ts"))
    j = valid.join(rates, cond, "left")

    w = Window.partitionBy("_pid").orderBy(F.col("rate_ts").desc_nulls_last())
    ranked = j.withColumn("_rn", F.row_number().over(w)).where(F.col("_rn") == 1)

    return (
        ranked
        .withColumn("as_applied_rate",
                    F.when(F.col("currency") == "USD", F.lit(1.0)).otherwise(F.col("rate")))
        .withColumn("as_applied_rate_ts",
                    F.when(F.col("currency") == "USD", F.col("pay_ts")).otherwise(F.col("rate_ts")))
        .withColumn("usd_amount", F.col("amount") * F.col("as_applied_rate"))
        .withColumn("settlement_date", utc_day(F.col("pay_ts")))
    )


@dp.materialized_view(name="payments_enriched")
def payments_enriched():
    e = build_enriched(SparkSession.active())
    return e.select(
        "payment_id", "currency", "amount", "pay_ts", "settlement_date",
        F.col("as_applied_rate").alias("rate"),
        F.col("as_applied_rate_ts").alias("rate_ts"),   # audit: as-applied rate timestamp
        "usd_amount",
    )


@dp.materialized_view(name="payments_rejects")
def payments_rejects():
    spark = SparkSession.active()
    pays = load_payments(spark)
    bad = pays.where(
        F.col("pay_ts").isNull() | F.col("amount").isNull() | F.col("currency").isNull()
    )
    return bad.select("payment_id", "currency", "amount", "pay_ts_raw",
                      F.lit("unparseable_or_missing_key").alias("reject_reason"))


@dp.materialized_view(name="usd_daily")
def usd_daily():
    e = build_enriched(SparkSession.active())
    conv = e.where(F.col("usd_amount").isNotNull())   # only rows with a valid pre-payment rate
    return (
        conv.groupBy("settlement_date")
            .agg(F.sum("usd_amount").alias("usd_total"))
            .select(F.col("settlement_date").cast("date").alias("settlement_date"), "usd_total")
    )
